// Function to construct and send transaction for contract call
async function sendTransaction() {
  const userInput = document.getElementById('user-input').value;
  const gasLimit = '20000'; // Replace with your desired gas limit

  try {
    const txCount = await provider.getTransactionCount(contractAddress);
    const tx = {
      from: '0x...', // Replace with your wallet address
      to: contractAddress,
      value: ethers.utils.parseUnits('0.01', 'ether'), // Replace with your desired transaction value
      gasLimit: gasLimit,
      gasPrice: ethers.utils.parseUnits('20', 'gwei'),
      nonce: txCount,
    };

    const signedTx = await provider.sendTransaction(tx);
    console.log(signedTx.hash);

    // Wait for the transaction to be mined
    const receipt = await provider.getTransactionReceipt(signedTx.hash);
    console.log(receipt);

  } catch (error) {
    console.error(error);
  }
}

